// src/pages/WoodDetail.js
import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css';
import './FormPage.css';
import './Manager.css';

// Đổi tên component từ FarmDetail thành WoodDetail
function WoodDetail() {
  // Thay đổi `farmId` thành `farmId` nếu bạn đang lấy chi tiết gỗ
  // Giả sử URL sẽ là /admin/woods/:farmId
  const { farmId } = useParams();
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const role = localStorage.getItem('role');

  // Đổi tên state từ `farm` thành `wood`
  const [wood, setWood] = useState(null);
  // Đổi tên state từ `activities` thành `woodActivities` hoặc `transactions`
  const [woodActivities, setWoodActivities] = useState([]); // Ví dụ: records of wood transactions/movements
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  // Cập nhật state cho form nhập xuất gỗ
  const [woodActivityFormData, setWoodActivityFormData] = useState({
    speciesName: '', // Tên loài gỗ
    date: '',        // Ngày nhập/xuất
    // Các trường khác cho nhập xuất gỗ. Ví dụ:
    quantity: 0,     // Số lượng (m3, kg, tấm, ...)
    unit: '',        // Đơn vị
    type: '',        // Loại giao dịch: 'import' (nhập), 'export' (xuất)
    reason: '',      // Lý do nhập/xuất
    source: '',      // Nguồn gốc (cho nhập)
    destination: '', // Nơi đến (cho xuất)
    // Các trường khác tùy theo model WoodActivity của bạn
    verifiedBy: '',
  });

  // Function to fetch wood details and wood activity records
  const fetchWoodDetails = useCallback(async () => { // Tên hàm đã được định nghĩa là `fetchWoodDetails`
    setLoading(true);
    setError('');
    setMessage('');
    try {
      // 1. Lấy chi tiết gỗ (nếu có một model "farmId" riêng)
      // Endpoint mới: /api/woods/:farmId
      // SỬA CỔNG: thay 10000 thành 5000
      const resWood = await axios.get(`http://localhost:10000/api/farms/${farmId}`, { // Thay đổi endpoint nếu bạn có API riêng cho từng item gỗ, hiện tại đang dùng API farms chung
        headers: { Authorization: `Bearer ${token}` },
      });
      // wood ở đây thực ra là farm, tôi sẽ đổi tên state bên dưới
      setWood(resWood.data);

      // Nếu có dữ liệu loài gỗ, đặt giá trị mặc định cho speciesName
      // Giả sử model Wood có một trường chứa các loài gỗ, ví dụ: woodSpecies[]
      if (resWood.data.loaiDongVatRung && resWood.data.loaiDongVatRung.length > 0) { // Đảm bảo đúng trường dữ liệu từ API farms
        setWoodActivityFormData(prev => ({
          ...prev,
          speciesName: resWood.data.loaiDongVatRung[0].tenLamSan // Đảm bảo đúng trường dữ liệu từ API farms
        }));
      }

      // 2. Lấy các bản ghi hoạt động nhập xuất gỗ cho mục gỗ này
      // Endpoint mới: /api/wood-activities/:farmId
      // SỬA CỔNG: thay 10000 thành 5000
      const resWoodActivities = await axios.get(`http://localhost:10000/api/wood-activities/${farmId}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setWoodActivities(resWoodActivities.data); // Cập nhật state

    } catch (err) {
      console.error('Lỗi khi tải chi tiết cơ sở gỗ hoặc bản ghi hoạt động:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Không thể tải chi tiết cơ sở gỗ hoặc bản ghi hoạt động.');
      // Chuyển hướng nếu không tìm thấy hoặc không được ủy quyền
      if (err.response && (err.response.status === 401 || err.response.status === 403 || err.response.status === 404)) {
        navigate('/admin/woods'); // Chuyển hướng đến trang quản lý gỗ
      }
    } finally {
      setLoading(false);
    }
  }, [farmId, token, navigate]); // Cập nhật dependency array

  useEffect(() => {
    console.log("WoodDetail.js: useEffect is running!");
    if (farmId && token) {
      fetchWoodDetails(); // SỬA TÊN HÀM TỪ fetchWoodBusinessDetails THÀNH fetchWoodDetails
    } else if (!farmId) {
      setError('Không có ID cơ sở gỗ để xem chi tiết.'); // Cập nhật thông báo
      setLoading(false);
    } else if (!token) {
      setError('Bạn cần đăng nhập để xem chi tiết cơ sở gỗ.'); // Cập nhật thông báo
      setLoading(false);
      navigate('/');
    }
  }, [farmId, token, navigate, fetchWoodDetails]); // SỬA TÊN HÀM TRONG DEPENDENCY ARRAY

  const handleWoodActivityFormChange = (e) => { // Đổi tên hàm
    const { name, value } = e.target;
    let newFormData = { ...woodActivityFormData };

    // Xử lý các trường đơn giản trực tiếp
    if (['speciesName', 'date', 'quantity', 'unit', 'type', 'reason', 'source', 'destination', 'verifiedBy'].includes(name)) {
      newFormData = {
        ...newFormData,
        [name]: name === 'quantity' ? parseInt(value, 10) || 0 : value, // Chuyển đổi quantity sang số
      };
    }
    // Không còn các trường lồng nhau như increase/decrease của FarmActivity

    setWoodActivityFormData(newFormData);
  };

  const handleAddWoodActivity = async (e) => { // Đổi tên hàm
    e.preventDefault();
    setMessage('');
    setError('');
    try {
      // Đảm bảo farmId được gửi cùng với dữ liệu form
      const dataToSend = {
        ...woodActivityFormData,
        farm: farmId, // Liên kết bản ghi hoạt động với farmId của cơ sở
      };
      // Endpoint mới: /api/wood-activities
      // SỬA CỔNG: thay 10000 thành 5000
      const res = await axios.post(`http://localhost:10000/api/wood-activities`, dataToSend, {
        headers: { Authorization: `Bearer ${token}` },
      });
      setMessage('Bản ghi hoạt động gỗ đã được thêm thành công!');
      // Cập nhật danh sách hoạt động
      setWoodActivities(prevActivities => [...prevActivities, res.data]);
      // Reset form, giữ speciesName nếu nó đã được chọn ở trên
      setWoodActivityFormData(prev => ({
        ...prev,
        date: '',
        quantity: 0,
        unit: '',
        type: '',
        reason: '',
        source: '',
        destination: '',
        verifiedBy: '',
      }));
    } catch (err) {
      console.error('Lỗi khi thêm bản ghi hoạt động gỗ:', err.response?.data || err.message);
      setError(err.response?.data?.message || 'Lỗi khi thêm bản ghi hoạt động gỗ.');
    }
  };

  const handleDeleteWoodActivity = async (activityId) => { // Đổi tên hàm
    const confirmed = window.confirm('Bạn có chắc chắn muốn xóa bản ghi này?');
    if (confirmed) {
      setMessage('');
      setError('');
      try {
        // Endpoint mới: /api/wood-activities/:activityId
        // SỬA CỔNG: thay 10000 thành 5000
        await axios.delete(`http://localhost:10000/api/wood-activities/${activityId}`, {
          headers: { Authorization: `Bearer ${token}` },
        });
        setMessage('Bản ghi đã được xóa thành công.');
        // Cập nhật danh sách hoạt động sau khi xóa
        setWoodActivities(prevActivities => prevActivities.filter(act => act._id !== activityId));
      } catch (err) {
        console.error('Lỗi khi xóa bản ghi hoạt động gỗ:', err.response?.data || err.message);
        setError(err.response?.data?.message || 'Lỗi khi xóa bản ghi hoạt động gỗ.');
      }
    }
  };

  if (loading) {
    return <div className="form-container"><p>Đang tải dữ liệu...</p></div>;
  }

  if (error) {
    return (
      <div className="form-container">
        <p style={{ color: 'red' }}>Lỗi: {error}</p>
        <button onClick={() => navigate('/admin/woods')}>Quay lại danh sách cơ sở gỗ</button>
      </div>
    );
  }

  if (!wood) { // wood ở đây là dữ liệu của Farm (cơ sở kinh doanh gỗ)
    return (
      <div className="form-container">
        <p style={{ color: 'orange' }}>Không tìm thấy thông tin cơ sở kinh doanh gỗ.</p>
        <button onClick={() => navigate('/admin/woods')}>Quay lại danh sách cơ sở gỗ</button>
      </div>
    );
  }

  return (
    <div className="form-container">
      {/* CSS tùy chỉnh vẫn giữ nguyên nếu bạn muốn các kiểu dáng form tương tự */}
      <style>
        {`
        .form-section-wrapper {
          flex: 1;
          min-width: 300px;
          padding: 3px;
          box-sizing: border-box;
        }

        .form-section-row {
          display: flex;
          gap: 15px;
          margin-bottom: 3px;
          align-items: center;
        }

        .form-group input[type="number"],
        .form-group input[type="text"],
        .form-group input[type="date"],
        .form-group select {
          width: 100%;
          box-sizing: border-box;
          padding: 8px 10px;
        }

        .form-container h2 {
          margin-bottom: 5px;
        }

        .form-container h3 {
          margin-top: 8px;
          margin-bottom: 3px;
        }

        .form-group {
            margin-bottom: 5px;
        }

        .form-group label {
          margin-bottom: 3px;
        }

        .modern-form .form-grid:first-of-type {
            margin-top: 0;
            padding-top: 0;
        }

        .modern-form .form-grid .form-group:last-of-type {
            margin-bottom: 0;
        }
        .modern-form h4 {
            margin-top: 5px;
            margin-bottom: 3px;
        }

        .modern-form .form-grid {
            gap: 15px;
        }
        `}
      </style>

      <h2>👁️ Nhật ký nhập, xuất: {wood.tenCoSo || 'N/A'}</h2> {/* Cập nhật hiển thị tên cơ sở */}
      
      <div className="form-grid">
        <div className="detail-group">
          <strong>Tên cơ sở:</strong> <p>{wood.tenCoSo || 'N/A'}</p> {/* Sử dụng tenCoSo từ API Farms */}
        </div>
        <div className="detail-group">
          <strong>Địa chỉ cơ sở:</strong> <p>{wood.diaChiCoSo || 'N/A'}</p> {/* Sử dụng diaChiCoSo từ API Farms */}
        </div>
        <div className="form-group detail-group">
          <label>Tên lâm sản (mặc định):</label>
          <select
            name="speciesName"
            value={woodActivityFormData.speciesName}
            onChange={handleWoodActivityFormChange}
            required
          >
            <option value="">-- Chọn lâm sản --</option>
            {/* Giả sử wood.loaiDongVatRung là một mảng các đối tượng { tenLamSan: string } */}
            {wood.loaiDongVatRung && wood.loaiDongVatRung.map((species, index) => (
              <option key={index} value={species.tenLamSan}>
                {species.tenLamSan}
              </option>
            ))}
          </select>
        </div>
      </div>

      <h3>Thêm bản ghi nhập/xuất gỗ mới:</h3>
      {message && <div className="success-message">{message}</div>}
      {error && <div className="error-message">{error}</div>}
      <form onSubmit={handleAddWoodActivity} className="modern-form">
        <div className="form-grid">
          <div className="form-group">
            <label>Ngày ghi nhận:</label>
            <input
              type="date"
              name="date"
              value={woodActivityFormData.date}
              onChange={handleWoodActivityFormChange}
              required
            />
          </div>
          <div className="form-group">
            <label>Loại giao dịch:</label>
            <select
              name="type"
              value={woodActivityFormData.type}
              onChange={handleWoodActivityFormChange}
              required
            >
              <option value="">-- Chọn loại --</option>
              <option value="import">Nhập</option>
              <option value="export">Xuất</option>
            </select>
          </div>
          <div className="form-group">
            <label>Số lượng:</label>
            <input
              type="number"
              name="quantity"
              value={woodActivityFormData.quantity}
              onChange={handleWoodActivityFormChange}
              min="0"
              required
            />
          </div>
          <div className="form-group">
            <label>Đơn vị:</label>
            <input
              type="text"
              name="unit"
              value={woodActivityFormData.unit}
              onChange={handleWoodActivityFormChange}
              required
            />
          </div>
          <div className="form-group">
            <label>Lý do:</label>
            <input
              type="text"
              name="reason"
              value={woodActivityFormData.reason}
              onChange={handleWoodActivityFormChange}
            />
          </div>
          {woodActivityFormData.type === 'import' && (
            <div className="form-group">
              <label>Nguồn gốc:</label>
              <input
                type="text"
                name="source"
                value={woodActivityFormData.source}
                onChange={handleWoodActivityFormChange}
              />
            </div>
          )}
          {woodActivityFormData.type === 'export' && (
            <div className="form-group">
              <label>Nơi đến:</label>
              <input
                type="text"
                name="destination"
                value={woodActivityFormData.destination}
                onChange={handleWoodActivityFormChange}
              />
            </div>
          )}
          <div className="form-group">
            <label>Người xác nhận:</label>
            <input
              type="text"
              name="verifiedBy"
              value={woodActivityFormData.verifiedBy}
              onChange={handleWoodActivityFormChange}
            />
          </div>
        </div>

        <button type="submit" className="submit-button">Thêm bản ghi</button>
      </form>

      <h3>Lịch sử nhập/xuất gỗ:</h3>
      <div className="activity-list-container">
        {woodActivities.length === 0 ? (
          <p>Chưa có bản ghi nhập/xuất gỗ nào cho cơ sở này.</p>
        ) : (
          <table className="activity-table">
            <thead>
              <tr>
                <th>STT</th>
                <th>Ngày</th>
                <th>Loài gỗ</th>
                <th>Loại giao dịch</th>
                <th>Số lượng</th>
                <th>Đơn vị</th>
                <th>Lý do</th>
                <th>Nguồn gốc</th>
                <th>Nơi đến</th>
                <th>Người xác nhận</th>
                {role === 'admin' && <th>Xóa</th>}
              </tr>
            </thead>
            <tbody>
              {woodActivities.map((activity, index) => {
                return (
                  <tr key={activity?._id || `temp-key-${Math.random()}`}>
                    <td>{index + 1}</td>
                    <td>{activity?.date ? new Date(activity.date).toLocaleDateString() : 'N/A'}</td>
                    <td>{activity?.speciesName ?? 'N/A'}</td>
                    <td>{activity?.type === 'import' ? 'Nhập' : (activity?.type === 'export' ? 'Xuất' : 'N/A')}</td>
                    <td>{activity?.quantity ?? 0}</td>
                    <td>{activity?.unit ?? 'N/A'}</td>
                    <td>{activity?.reason ?? 'N/A'}</td>
                    <td>{activity?.source ?? 'N/A'}</td>
                    <td>{activity?.destination ?? 'N/A'}</td>
                    <td>{activity?.verifiedBy ?? 'N/A'}</td>
                    {role === 'admin' && (
                      <td>
                        <button onClick={() => handleDeleteWoodActivity(activity._id)} className="delete-button">Xóa</button>
                      </td>
                    )}
                  </tr>
                );
              })}
            </tbody>
          </table>
        )}
      </div>
      <div className="detail-actions">
        <button onClick={() => navigate('/admin/woods')} className="cancel-button">Quay lại danh sách cơ sở gỗ</button>
      </div>
    </div>
  );
}

export default WoodDetail;
